from openai import OpenAI

client = OpenAI()

def lookup_stock(symbol):
    # In production: real stock data from Bloomberg/TMX/NASDAQ etc.
    return {
        "AAPL": {"name": "Apple", "price": 180},
        "TSLA": {"name": "Tesla", "price": 750},
        "NFLX": {"name": "Netflix", "price": 360},
    }.get(symbol, {"error": f"No such stock: {symbol}"})

# In production: use a real function instead of this stub
tools = [
    {
        "type": "function",
        "function": {
            "name": "lookup_stock",
            "description": "Get current price for a stock ticker symbol (AAPL, TSLA, etc.).",
            "parameters": {
                "type": "object",
                "properties": {"symbol": {"type": "string"}},
                "required": ["symbol"],
                "additionalProperties": False,
            },
        }
    }
]

def chat_loop():
    user_input = input("What should we do? ")
    messages = [{"role": "user", "content": user_input}]

    while True:
        response = client.chat.completions.create(
            model="gpt-4o",
            tools=tools,
            messages=messages
        )
        message = response.choices[0].message

        if message.content:  # User message
            print(f"\nUser: {message.content}")
        if message.tool_calls:  # Function call request
            for tool_call in message.tool_calls:
                if tool_call.function.name == "lookup_stock":
                    args = json.loads(tool_call.function.arguments)
                    result = lookup_stock(args["symbol"])
                    print(f"\nAssistant (stock lookup): {result}")

                    # Send function result back to model
                    messages.append({
                        "role": "user",
                        "content": [
                            {"type": "tool_use", **tool_call.model_dump()},
                            {
                                "type": "function_call_result",
                                "call_id": tool_call.id,
                                "content": json.dumps(result),
                            }
                        ]
                    })
        if message.stop_reason == "end_turn":
            print("\nAssistant: Here's the final answer!")
            print(message.content)
            break

chat_loop()
