def get_time(timezone):
    """Return current time in requested timezone."""
    tz = pytz.timezone(timezone)
    now = datetime.now(tz)
    return now.strftime("%Y-%m-%d %H:%M:%S %Z%z")

tools = [
    {
        "name": "get_weather",
        "description": "Get the current weather for a given location.",
        "input_schema": {
            "type": "object",
            "properties": {
                "location": {
                    "type": "string",
                    "description": "The city or location to get weather for."
                }
            },
            "required": ["location"]
        }
    },
    {
        "name": "get_time",
        "description": "Get the current time in a given timezone.",
        "input_schema": {
            "type": "object",
            "properties": {
                "timezone": {
                    "type": "string",
                    "description": "The timezone to get the time for (e.g., 'Asia/Tokyo')."
                }
            },
            "required": ["timezone"]
        }
    }
]

context_messages = [
    {
        "role": "user",
        "content": """You are a helpful assistant that can answer questions about the weather and time.

You have access to two tools: get_weather and get_time. Use them as needed to provide accurate information."""
    }
]

def ask_with_tools(question):
    messages = context_messages + [
        {
            "role": "user",
            "content": question
        }
    ]

    response = client.messages.create(
        model=MODEL_NAME,
        max_tokens=4096,
        tools=tools,
        tool_choice="auto",  # or "never_auto" to always use the tool
        messages=messages
    )

    if response.stop_reason == "tool_use":
        tool_name = response.content[0].name
        tool_input = response.content[0].input

        print(f"\nAssistant wants to use tool: {tool_name}")
        print("Tool input:", tool_input)

        # Call the appropriate tool function and add the result to messages
        if tool_name == "get_weather":
            result = get_weather(tool_input["location"])
        elif tool_name == "get_time":
            result = get_time(tool_input["timezone"])

        messages.append({
            "role": "tool",
            "content": str(result),
            "tool_name": tool_name
        })

        # Get final response with tool results included
        final_response = client.messages.create(
            model=MODEL_NAME,
            max_tokens=4096,
            tools=tools,
            tool_choice="auto",  # keep auto to re-evaluate if needed
            messages=messages
        )

        context_messages.append({
            "role": "tool",
            "content": str(result),
            "tool_name": tool_name
        })
        context_messages.append(final_response.content[0])

        return final_response.content[0].text

    else:
        return None


# Example usage
answer = ask_with_tools("What's the weather in Tokyo and what time is it in New York?")
if answer:
    print("\nFinal answer:")
    print(answer)
