from typing import List

import rich
from pydantic import BaseModel

from ollama import Client


# Define a simple schema for our responses
class FriendInfo(BaseModel):
  name: str
  age: int
  is_available: bool


class GetFriendsResponse(BaseModel):
  friends: List[FriendInfo]


client = Client()
messages = []
while True:
  user_input = input('Chat with the model (or type "q" to quit): ')
  if user_input == 'q':
    break

  messages.append({'role': 'user', 'content': user_input})

  response = client.chat(
    'llama3.2',
    messages=messages,
    format=GetFriendsResponse.model_json_schema(),  # Pass in our schema for the model to return
  )

  messages.append({'role': 'assistant', 'content': response.message.content})
  rich.print(response.message.content)

  # Extract and parse the JSON from the response
  start_index = None
  end_index = None
  for i, part in enumerate(response.message.content):
    if isinstance(part, dict) and part.get('type') == 'text':
      text = part['text']
      if text.strip().lower().startswith('friends:'):
        start_index = i + 1
      elif start_index is not None:
        end_index = i
        break

  if start_index is not None and end_index is None:
    # If the entire response was the JSON block, include everything after the header
    parsed_response = GetFriendsResponse.model_validate_json(
      {'friends': [part for part in response.message.content[start_index:]]}
    )
    rich.print(parsed_response)
  elif start_index is not None and end_index is not None:
    # If the JSON is in the middle of the response, parse only the JSON part
    json_text = ''.join(
      str(part['text']) for part in response.message.content[start_index:end_index]
    ).strip()
    try:
      parsed_json = GetFriendsResponse.model_validate_json({'friends': json_text})
      rich.print(parsed_json)
    except Exception as e:
      print(f'Invalid JSON response: {e}')
  else:
    # If there is no clear JSON block, include the entire response
    parsed_response = GetFriendsResponse.model_validate_json(
      {'friends': [part for part in response.message.content]}
    )
    rich.print(parsed_response)
